import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, 
  Briefcase, 
  User, 
  BookOpen, 
  Heart, 
  Folder,
  Home,
  Star,
  Calendar,
  Settings,
  Edit3,
  Trash2,
  X,
  Check,
  Clock,
  Users,
  MoreVertical,
  UserPlus,
  FolderPlus,
  ChevronRight,
  ChevronDown
} from 'lucide-react';

const GroupsView = ({ 
  folders, 
  selectedGroup,
  onSelectGroup,
  showCreateGroup,
  setShowCreateGroup,
  newGroupName,
  setNewGroupName,
  newGroupIcon,
  setNewGroupIcon,
  onCreateGroup,
  editingGroup,
  setEditingGroup,
  editGroupName,
  setEditGroupName,
  onEditGroup,
  onDeleteGroup,
  newGroupExpirationDate,
  setNewGroupExpirationDate,
  newGroupIsShared,
  setNewGroupIsShared,
  onMoveFolder,
  onAddPersonToFolder,
  onCreateSubFolder,
  onReorderFolders
}) => {
  const iconComponents = {
    Briefcase,
    User,
    BookOpen,
    Heart,
    Folder,
    Home,
    Star,
    Calendar,
    Settings
  };

  const iconOptions = Object.keys(iconComponents);

  const renderIcon = (iconName) => {
    const IconComponent = iconComponents[iconName] || Folder;
    return <IconComponent className="w-4 h-4 text-neutral-400" />;
  };

  const handleCreateGroup = () => {
    onCreateGroup();
  };

  const handleEditGroup = (groupId) => {
    onEditGroup(groupId, editGroupName);
  };

  const startEdit = (group) => {
    setEditingGroup(group.id);
    setEditGroupName(group.name);
  };

  const cancelEdit = () => {
    setEditingGroup(null);
    setEditGroupName('');
  };

  // State for dropdown menu
  const [openDropdown, setOpenDropdown] = useState(null);
  const dropdownRef = useRef(null);

  // State for drag and drop
  const [draggedFolder, setDraggedFolder] = useState(null);
  const [dragOverFolder, setDragOverFolder] = useState(null);
  const [dragOverPosition, setDragOverPosition] = useState(null);

  // State for expanded folders
  const [expandedFolders, setExpandedFolders] = useState(new Set());

  // State for adding people
  const [showAddPeople, setShowAddPeople] = useState(null);
  const [showCreateSubFolder, setShowCreateSubFolder] = useState(null);
  const [newSubFolderName, setNewSubFolderName] = useState('');

  // Mock users data for adding to folders
  const availableUsers = [
    { id: 1, name: 'John Doe', avatar: 'https://images.pexels.com/photos/1130626/pexels-photo-1130626.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop' },
    { id: 2, name: 'Sarah Chen', avatar: 'https://images.pexels.com/photos/1130626/pexels-photo-1130626.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop' },
    { id: 3, name: 'Mike Johnson', avatar: 'https://images.pexels.com/photos/1130626/pexels-photo-1130626.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop' }
  ];

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setOpenDropdown(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const toggleDropdown = (groupId, e) => {
    e.stopPropagation();
    setOpenDropdown(openDropdown === groupId ? null : groupId);
  };

  // Drag and drop handlers
  const handleDragStart = (e, folder) => {
    setDraggedFolder(folder);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e, folder) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    setDragOverFolder(folder.id);
  };

  const handleDragOverBetween = (e, position, folderId) => {
    e.preventDefault();
    e.stopPropagation();
    setDragOverPosition({ position, folderId });
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setDragOverFolder(null);
  };

  const handleDrop = (e, targetFolder) => {
    e.preventDefault();
    if (draggedFolder && draggedFolder.id !== targetFolder.id) {
      onMoveFolder(draggedFolder.id, targetFolder.id);
    }
    setDraggedFolder(null);
    setDragOverFolder(null);
    setDragOverPosition(null);
  };

  const handleDropBetween = (e, position, targetFolderId) => {
    e.preventDefault();
    e.stopPropagation();
    if (draggedFolder && draggedFolder.id !== targetFolderId) {
      onReorderFolders(draggedFolder.id, targetFolderId, position);
    }
    setDraggedFolder(null);
    setDragOverFolder(null);
    setDragOverPosition(null);
  };

  const handleDropToRoot = (e) => {
    e.preventDefault();
    if (draggedFolder) {
      onMoveFolder(draggedFolder.id, null);
    }
    setDraggedFolder(null);
    setDragOverFolder(null);
    setDragOverPosition(null);
  };

  const handleDragEnd = () => {
    setDraggedFolder(null);
    setDragOverFolder(null);
    setDragOverPosition(null);
  };

  // Folder expansion
  const toggleFolderExpansion = (folderId) => {
    const newExpanded = new Set(expandedFolders);
    if (newExpanded.has(folderId)) {
      newExpanded.delete(folderId);
    } else {
      newExpanded.add(folderId);
    }
    setExpandedFolders(newExpanded);
  };

  // Create sub-folder
  const handleCreateSubFolder = (parentId) => {
    if (newSubFolderName.trim()) {
      onCreateSubFolder(parentId, newSubFolderName);
      setNewSubFolderName('');
      setShowCreateSubFolder(null);
    }
  };

  // Add person to folder
  const handleAddPersonToFolder = (folderId, user) => {
    onAddPersonToFolder(folderId, user);
    setShowAddPeople(null);
  };

  // Get sub-folders
  const getSubFolders = (parentId) => {
    if (!folders || !Array.isArray(folders)) {
      return [];
    }
    return folders.filter(folder => folder.parentId === parentId);
  };

  // Get root folders (no parent)
  const getRootFolders = () => {
    if (!folders || !Array.isArray(folders)) {
      return [];
    }
    return folders.filter(folder => !folder.parentId);
  };

  if (showCreateGroup) {
    return (
      <div className="p-6 flex-1">
        <h3 className="text-white text-lg font-semibold mb-4">Create New Folder</h3>

        <div className="space-y-4">
          <div>
            <label className="block text-white text-sm font-medium mb-2">Folder Name</label>
            <input
              type="text"
              placeholder="Enter folder name..."
              value={newGroupName}
              onChange={(e) => setNewGroupName(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleCreateGroup()}
              className="w-full border border-neutral-600 rounded-lg px-3 py-2 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent bg-transparent"
              autoFocus
            />
          </div>

          <div>
            <label className="block text-white text-sm font-medium mb-2">Icon</label>
            <div className="grid grid-cols-3 gap-2">
              {iconOptions.map(icon => (
                <button
                  key={icon}
                  onClick={() => setNewGroupIcon(icon)}
                  className={`p-2 border rounded-lg flex items-center justify-center transition-colors ${
                    newGroupIcon === icon 
                      ? 'border-white bg-neutral-700' 
                      : 'border-neutral-600 hover:border-neutral-500'
                  }`}
                >
                  {renderIcon(icon)}
                </button>
              ))}
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              onClick={() => setShowCreateGroup(false)}
              className="flex-1 px-4 py-2 border border-neutral-600 rounded-lg text-white hover:bg-neutral-800 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleCreateGroup}
              className="flex-1 px-4 py-2 bg-neutral-800 text-white rounded-lg hover:bg-neutral-800 border border-neutral-600 transition-colors"
            >
              Create
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Render folder component recursively
  const renderFolder = (folder, level = 0) => {
    const subFolders = getSubFolders(folder.id);
    const hasSubFolders = subFolders.length > 0;
    const isExpanded = expandedFolders.has(folder.id);
    const isDragOver = dragOverFolder === folder.id;

    return (
      <div key={folder.id} style={{ marginLeft: `${level * 20}px` }} className="mb-2">
        {/* Drop zone acima do folder para reordenação */}
        {level === 0 && (
          <div
            className={`h-2 transition-all duration-200 ${
              dragOverPosition?.position === 'above' && dragOverPosition?.folderId === folder.id
                ? 'bg-blue-300 rounded'
                : ''
            }`}
            onDragOver={(e) => handleDragOverBetween(e, 'above', folder.id)}
            onDrop={(e) => handleDropBetween(e, 'above', folder.id)}
          />
        )}
        <div 
          className={`flex items-center justify-between p-3 border rounded-lg hover:bg-neutral-800 transition-colors cursor-pointer ${
            selectedGroup?.id === folder.id ? 'bg-neutral-800 border-neutral-600' : 'border-neutral-700'
          } ${
            isDragOver ? 'border-blue-500 bg-blue-900/20' : ''
          }`}
          onClick={() => {
            onSelectGroup(folder);
            if (hasSubFolders) {
              toggleFolderExpansion(folder.id);
            }
          }}
          draggable={!editingGroup}
          onDragStart={(e) => handleDragStart(e, folder)}
          onDragOver={(e) => handleDragOver(e, folder)}
          onDragLeave={handleDragLeave}
          onDrop={(e) => handleDrop(e, folder)}
          onDragEnd={handleDragEnd}
        >
          <div className="flex items-center gap-3">
            {renderIcon(folder.icon)}

            {editingGroup === folder.id ? (
              <input
                type="text"
                value={editGroupName}
                onChange={(e) => setEditGroupName(e.target.value)}
                onKeyPress={(e) => {
                  if (e.key === 'Enter') handleEditGroup(folder.id);
                  if (e.key === 'Escape') cancelEdit();
                }}
                onBlur={() => handleEditGroup(folder.id)}
                className="bg-transparent text-white focus:outline-none border-b border-white"
                autoFocus
              />
            ) : (
              <span className="text-white">{folder.name}</span>
            )}

            {/* Show assigned people */}
            {folder.assignedUsers && folder.assignedUsers.length > 0 && (
              <div className="flex -space-x-1">
                {folder.assignedUsers.slice(0, 3).map((user, index) => (
                  <img
                    key={user.id}
                    src={user.avatar}
                    alt={user.name}
                    className="w-5 h-5 rounded-full border border-neutral-600"
                    title={user.name}
                  />
                ))}
                {folder.assignedUsers.length > 3 && (
                  <div className="w-5 h-5 rounded-full bg-neutral-600 border border-neutral-600 flex items-center justify-center text-xs text-neutral-300">
                    +{folder.assignedUsers.length - 3}
                  </div>
                )}
              </div>
            )}
          </div>

          <div className="flex items-center gap-2">
            {editingGroup === folder.id ? (
              <>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    cancelEdit();
                  }}
                  className="text-neutral-400 hover:text-white transition-colors"
                >
                  <X className="w-4 h-4" />
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleEditGroup(folder.id);
                  }}
                  className="text-neutral-400 hover:text-white transition-colors"
                >
                  <Check className="w-4 h-4" />
                </button>
              </>
            ) : (
              <>
                {/* Counter */}
                <span className="text-xs bg-neutral-700 text-neutral-400 w-5 h-5 rounded flex items-center justify-center">
                  {folder.count}
                </span>

                {/* Three-dot menu */}
                <div className="relative" ref={openDropdown === folder.id ? dropdownRef : null}>
                  <button
                    onClick={(e) => toggleDropdown(folder.id, e)}
                    className="text-neutral-400 hover:text-white transition-colors p-1 hover:bg-neutral-600 rounded"
                  >
                    <MoreVertical className="w-4 h-4" />
                  </button>

                  {/* Dropdown menu */}
                  {openDropdown === folder.id && (
                    <div className="absolute right-0 top-8 bg-neutral-800 border border-neutral-700 rounded-lg shadow-lg z-10 min-w-[160px]">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          startEdit(folder);
                          setOpenDropdown(null);
                        }}
                        className="w-full flex items-center gap-2 p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors text-sm first:rounded-t-lg"
                      >
                        <Edit3 className="w-4 h-4" />
                        <span>Edit</span>
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          setShowCreateSubFolder(folder.id);
                          setOpenDropdown(null);
                        }}
                        className="w-full flex items-center gap-2 p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors text-sm"
                      >
                        <FolderPlus className="w-4 h-4" />
                        <span>Add Sub-folder</span>
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          setShowAddPeople(folder.id);
                          setOpenDropdown(null);
                        }}
                        className="w-full flex items-center gap-2 p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors text-sm"
                      >
                        <UserPlus className="w-4 h-4" />
                        <span>Add People</span>
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          onDeleteGroup(folder.id);
                          setOpenDropdown(null);
                        }}
                        className="w-full flex items-center gap-2 p-2 text-neutral-400 hover:text-red-500 hover:bg-neutral-700 transition-colors text-sm last:rounded-b-lg"
                      >
                        <Trash2 className="w-4 h-4" />
                        <span>Delete</span>
                      </button>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        </div>

        {/* Sub-folder creation form */}
        {showCreateSubFolder === folder.id && (
          <div className="mt-3 p-3 bg-neutral-800 border border-neutral-700 rounded-lg" style={{ marginLeft: `${(level + 1) * 20}px` }}>
            <input
              type="text"
              placeholder="Enter sub-folder name..."
              value={newSubFolderName}
              onChange={(e) => setNewSubFolderName(e.target.value)}
              onKeyPress={(e) => {
                if (e.key === 'Enter') handleCreateSubFolder(folder.id);
                if (e.key === 'Escape') setShowCreateSubFolder(null);
              }}
              className="w-full bg-transparent text-white border border-neutral-600 rounded px-2 py-1 focus:outline-none focus:border-white"
              autoFocus
            />
            <div className="flex gap-2 mt-2">
              <button
                onClick={() => handleCreateSubFolder(folder.id)}
                className="px-3 py-1 bg-neutral-700 text-white rounded text-sm hover:bg-neutral-600"
              >
                Create
              </button>
              <button
                onClick={() => setShowCreateSubFolder(null)}
                className="px-3 py-1 border border-neutral-600 text-white rounded text-sm hover:bg-neutral-700"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {/* Add people form */}
        {showAddPeople === folder.id && (
          <div className="mt-3 p-3 bg-neutral-800 border border-neutral-700 rounded-lg" style={{ marginLeft: `${(level + 1) * 20}px` }}>
            <h4 className="text-white text-sm font-medium mb-2">Add People to Folder</h4>
            <div className="space-y-2">
              {availableUsers.map(user => (
                <button
                  key={user.id}
                  onClick={() => handleAddPersonToFolder(folder.id, user)}
                  className="w-full flex items-center gap-2 p-2 hover:bg-neutral-700 rounded text-left"
                >
                  <img src={user.avatar} alt={user.name} className="w-6 h-6 rounded-full" />
                  <span className="text-white text-sm">{user.name}</span>
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowAddPeople(null)}
              className="mt-2 px-3 py-1 border border-neutral-600 text-white rounded text-sm hover:bg-neutral-700"
            >
              Cancel
            </button>
          </div>
        )}

        {/* Render sub-folders */}
        {isExpanded && (
          <div className="mt-2 space-y-2">
            {subFolders.map(subFolder => renderFolder(subFolder, level + 1))}

            {/* Botão para criar nova subfolder - sempre visível quando expandido */}
            <div style={{ marginLeft: `${(level + 1) * 20}px` }}>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowCreateSubFolder(folder.id);
                }}
                className="flex items-center space-x-2 p-2 text-sm text-neutral-400 hover:text-white hover:bg-neutral-700 rounded-md transition-colors"
              >
                <FolderPlus className="w-4 h-4" />
                <span>Create New Subfolder</span>
              </button>
            </div>
          </div>
        )}

        {/* Drop zone abaixo do folder para reordenação */}
        {level === 0 && (
          <div
            className={`h-2 transition-all duration-200 ${
              dragOverPosition?.position === 'below' && dragOverPosition?.folderId === folder.id
                ? 'bg-blue-300 rounded'
                : ''
            }`}
            onDragOver={(e) => handleDragOverBetween(e, 'below', folder.id)}
            onDrop={(e) => handleDropBetween(e, 'below', folder.id)}
          />
        )}
      </div>
    );
  };

  return (
    <div className="p-6 flex-1">
      <h3 className="text-white text-lg font-semibold mb-4">Folders</h3>
      <div 
        className="space-y-3"
        onDragOver={(e) => {
          e.preventDefault();
          setDragOverFolder(null);
        }}
        onDrop={handleDropToRoot}
      >
        {getRootFolders().map(folder => renderFolder(folder))}

        <button 
          onClick={() => setShowCreateGroup(true)}
          className="w-full flex items-center gap-3 p-3 bg-neutral-800 rounded-lg hover:bg-neutral-600 transition-colors text-white"
        >
          <Plus className="w-4 h-4" />
          <span className="">Create new folder</span>
        </button>
      </div>
    </div>
  );
};

export default GroupsView;
